import React, { useEffect, useState } from 'react';
import api from '../api';

export default function ServiciosPendientesAdmin() {
  const [servicios, setServicios] = useState([]);
  const [cargando, setCargando] = useState(true);
  const [expandido, setExpandido] = useState(null);

  const cargar = async () => {
    try {
      const res = await api.get('/ofertas/admin/pendientes-con-ofertas');
      setServicios(res.data);
    } catch {}
    finally { setCargando(false); }
  };

  useEffect(() => {
    cargar();
    const intervalo = setInterval(cargar, 15000);
    return () => clearInterval(intervalo);
  }, []);

  if (cargando) return <p className="loading">Cargando servicios pendientes...</p>;

  if (servicios.length === 0) {
    return (
      <div style={estilos.vacio}>
        <p style={{ fontSize: 48 }}>📡</p>
        <p style={{ color: '#999' }}>No hay servicios pendientes en este momento</p>
      </div>
    );
  }

  return (
    <div>
      <h2 className="titulo">🚕 Servicios Pendientes en Tiempo Real</h2>
      <p style={{ color: '#888', marginBottom: 20 }}>Se actualiza cada 15 segundos</p>

      {servicios.map(s => (
        <div key={s.id} style={estilos.servicioCard}>
          {/* Header del servicio */}
          <div style={estilos.servicioHeader} onClick={() => setExpandido(expandido === s.id ? null : s.id)}>
            <div style={{ flex: 1 }}>
              <div style={estilos.servicioTitulo}>
                <span style={estilos.clienteNombre}>👤 {s.clienteNombre}</span>
                <span style={estilos.metodoPago}>{s.metodoPago?.toUpperCase()}</span>
                {s.ofertas?.length > 0 && (
                  <span style={estilos.ofertasBadge}>{s.ofertas.length} oferta{s.ofertas.length > 1 ? 's' : ''}</span>
                )}
                {(!s.ofertas || s.ofertas.length === 0) && (
                  <span style={estilos.sinOfertas}>Sin ofertas</span>
                )}
              </div>
              <div style={estilos.servicioRuta}>
                <span>📍 {s.origen}</span>
                <span style={{ margin: '0 8px', color: '#aaa' }}>→</span>
                <span>🏁 {s.destino}</span>
              </div>
              <div style={{ fontSize: 12, color: '#aaa', marginTop: 4 }}>
                Solicitado: {new Date(s.creadoEn).toLocaleString('es-CO')}
                {s.clienteCelular && <span style={{ marginLeft: 12 }}>📞 {s.clienteCelular}</span>}
              </div>
            </div>
            <span style={{ fontSize: 20, color: '#999' }}>{expandido === s.id ? '▲' : '▼'}</span>
          </div>

          {/* Ofertas expandidas */}
          {expandido === s.id && (
            <div style={estilos.ofertasContainer}>
              <h4 style={{ margin: '0 0 12px', color: '#555' }}>💰 Ofertas recibidas</h4>
              {(!s.ofertas || s.ofertas.length === 0) ? (
                <p style={{ color: '#999', textAlign: 'center', padding: 20 }}>
                  Ningún conductor ha ofertado aún
                </p>
              ) : (
                s.ofertas.map((o, i) => (
                  <div key={o.id} style={[estilos.ofertaItem, i === 0 && estilos.ofertaMejor]}>
                    <div style={{ display: 'flex', alignItems: 'center', gap: 12 }}>
                      {i === 0 && <span style={{ fontSize: 20 }}>🥇</span>}
                      <div style={{ flex: 1 }}>
                        <div style={{ fontWeight: 'bold', fontSize: 15 }}>🚕 {o.conductorNombre}</div>
                        <div style={{ fontSize: 13, color: '#888' }}>
                          Placa: <strong style={{ color: '#FFC107' }}>{o.conductorPlaca || '—'}</strong>
                          {o.conductorCelular && <span style={{ marginLeft: 12 }}>📞 {o.conductorCelular}</span>}
                        </div>
                        {o.mensaje && <div style={{ fontSize: 13, color: '#666', fontStyle: 'italic', marginTop: 2 }}>"{o.mensaje}"</div>}
                        <div style={{ fontSize: 11, color: '#aaa', marginTop: 2 }}>
                          {new Date(o.creadoEn).toLocaleTimeString('es-CO')}
                        </div>
                      </div>
                      <div style={{ textAlign: 'right' }}>
                        <div style={{ fontSize: 22, fontWeight: 'bold', color: '#2E7D32' }}>
                          ${o.monto?.toLocaleString('es-CO')}
                        </div>
                        <div style={{
                          fontSize: 11, padding: '2px 8px', borderRadius: 8,
                          background: o.estado === 'aceptada' ? '#2E7D32' : o.estado === 'rechazada' ? '#E53935' : '#FFC107',
                          color: o.estado === 'pendiente' ? '#000' : '#fff',
                          display: 'inline-block', marginTop: 4,
                        }}>
                          {o.estado?.toUpperCase() || 'PENDIENTE'}
                        </div>
                      </div>
                    </div>
                  </div>
                ))
              )}

              {/* Datos del cliente */}
              <div style={estilos.datosCliente}>
                <h4 style={{ margin: '0 0 8px', color: '#555' }}>👤 Datos del cliente</h4>
                <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: 8, fontSize: 13 }}>
                  <div><span style={{ color: '#999' }}>Nombre:</span> <strong>{s.clienteNombre}</strong></div>
                  <div><span style={{ color: '#999' }}>Celular:</span> <strong>{s.clienteCelular || '—'}</strong></div>
                  <div><span style={{ color: '#999' }}>Pago:</span> <strong>{s.metodoPago?.toUpperCase()}</strong></div>
                  <div><span style={{ color: '#999' }}>Tarifa mín:</span> <strong>${(s.tarifaMinima || 8000).toLocaleString('es-CO')}</strong></div>
                </div>
                {s.ubicacionGPS && (
                  <a href={`https://www.google.com/maps?q=${s.ubicacionGPS.lat},${s.ubicacionGPS.lng}`}
                    target="_blank" rel="noopener noreferrer"
                    style={{ color: '#1565C0', fontSize: 13, fontWeight: '600', display: 'block', marginTop: 8 }}>
                    📌 Ver ubicación del cliente en mapa
                  </a>
                )}
                {s.requisitos?.length > 0 && (
                  <div style={{ marginTop: 8 }}>
                    <span style={{ color: '#999', fontSize: 12 }}>Requisitos: </span>
                    {s.requisitos.map(r => (
                      <span key={r} style={{ background: '#E3F2FD', color: '#1565C0', borderRadius: 6, padding: '2px 8px', fontSize: 12, marginRight: 4 }}>
                        {r === 'maletas' ? '🧳' : r === 'discapacitado' ? '♿' : r === 'bicicleta' ? '🚲' : r === 'aireAcondicionado' ? '❄️' : '🐾'} {r}
                      </span>
                    ))}
                  </div>
                )}
              </div>
            </div>
          )}
        </div>
      ))}
    </div>
  );
}

const estilos = {
  vacio: { textAlign: 'center', padding: 60 },
  servicioCard: {
    background: '#fff', borderRadius: 16, marginBottom: 16,
    boxShadow: '0 2px 12px rgba(0,0,0,0.08)', overflow: 'hidden',
  },
  servicioHeader: {
    display: 'flex', alignItems: 'center', padding: 20,
    cursor: 'pointer', borderBottom: '1px solid #f0f0f0',
    background: 'linear-gradient(135deg, #fff9e6, #fff)',
  },
  servicioTitulo: { display: 'flex', alignItems: 'center', gap: 10, marginBottom: 6, flexWrap: 'wrap' },
  clienteNombre: { fontWeight: 'bold', fontSize: 17 },
  metodoPago: { background: '#E3F2FD', color: '#1565C0', borderRadius: 8, padding: '2px 10px', fontSize: 12, fontWeight: 'bold' },
  ofertasBadge: { background: '#FFC107', color: '#000', borderRadius: 8, padding: '2px 10px', fontSize: 12, fontWeight: 'bold' },
  sinOfertas: { background: '#f5f5f5', color: '#999', borderRadius: 8, padding: '2px 10px', fontSize: 12 },
  servicioRuta: { fontSize: 14, color: '#555' },
  ofertasContainer: { padding: 20 },
  ofertaItem: {
    background: '#f9f9f9', borderRadius: 12, padding: 14,
    marginBottom: 10, borderLeft: '4px solid #ddd',
  },
  ofertaMejor: { borderLeft: '4px solid #2E7D32', background: '#F1F8E9' },
  datosCliente: {
    background: '#f5f5f5', borderRadius: 12, padding: 16, marginTop: 16,
  },
};
